import { NextResponse } from "next/server";
import { getServerSession } from "next-auth";
import { authOptions } from "@/lib/auth";
import { getProperties } from "@/lib/volkern-mcp";
// import prisma from "@/lib/prisma";

export async function GET(request: Request) {
    // 1. Validate Session for Admin
    const session = await getServerSession(authOptions);

    if (!session || (session.user as any)?.role !== "ADMIN") {
        return NextResponse.json({ error: "Unauthorized access" }, { status: 401 });
    }

    try {
        // 2. Fetch properties securely
        // In Phase 5, this will sync between Prisma DB and MCP. For now we use MCP directly.
        const properties = await getProperties();
        return NextResponse.json({ success: true, data: properties });
    } catch (error) {
        console.error("Internal Admin API Error:", error);
        return NextResponse.json({ error: "Failed to fetch internal properties" }, { status: 500 });
    }
}

import { createMockProperty, updateMockProperty } from "@/lib/mock-db";

export async function POST(request: Request) {
    const session = await getServerSession(authOptions);

    if (!session || (session.user as any)?.role !== "ADMIN") {
        return NextResponse.json({ error: "Unauthorized access" }, { status: 401 });
    }

    try {
        const body = await request.json();
        // TODO Phase 5: Create property in PostreSQL via Prisma
        // const newProp = await prisma.property.create({ data: body });
        const newProp = await createMockProperty(body);

        return NextResponse.json({ success: true, message: "Property created mock", data: newProp });
    } catch (error) {
        return NextResponse.json({ error: "Invalid payload" }, { status: 400 });
    }
}

export async function PUT(request: Request) {
    const session = await getServerSession(authOptions);

    if (!session || (session.user as any)?.role !== "ADMIN") {
        return NextResponse.json({ error: "Unauthorized access" }, { status: 401 });
    }

    try {
        const body = await request.json();
        // TODO Phase 5: Update property in PostreSQL via Prisma
        // const updatedProp = await prisma.property.update({ where: { id: body.id }, data: body });
        const propIdentifier = body.sku || body.id;
        if (!propIdentifier) {
            return NextResponse.json({ error: "Missing identity" }, { status: 400 });
        }
        const updatedProp = await updateMockProperty(propIdentifier, body);

        return NextResponse.json({ success: true, message: "Property updated mock", data: updatedProp });
    } catch (error) {
        return NextResponse.json({ error: "Invalid payload" }, { status: 400 });
    }
}

"use client";

import * as React from "react";
import { useState, useEffect } from "react";
import Link from "next/link";
import {
  Bed,
  Bath,
  Square,
  Maximize,
  Car,
  CheckCircle,
  MapPin,
  Search,
  X
} from "lucide-react";

export default function Home() {
  const [allProperties, setAllProperties] = useState<any[]>([]);
  const [filteredProperties, setFilteredProperties] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);

  const [filters, setFilters] = useState({
    location: "",
    operation: "all",
    type: "all"
  });

  useEffect(() => {
    async function fetchProps() {
      try {
        const res = await fetch('/api/properties');
        if (!res.ok) throw new Error("Failed to fetch");
        const json = await res.json();
        const props = json.data || [];
        setAllProperties(props);
        setFilteredProperties(props);
      } catch (e) {
        console.error("No properties fetched:", e);
        // Fallback mocks
        const mocks = [
          { id: '1', name: 'Apartamento Playa', price: 450000, currency: 'EUR', location: 'M├ílaga', specs: { beds: 2, baths: 2, builtArea: 90, totalArea: 120, parking: 1, availability: 'Disponible' }, operation: 'venta', image: 'https://images.unsplash.com/photo-1560518883-ce09059ee712?auto=format&fit=crop&w=800&q=80' }
        ];
        setAllProperties(mocks);
        setFilteredProperties(mocks);
      } finally {
        setLoading(false);
      }
    }
    fetchProps();
  }, []);

  const normalizeText = (text: string) =>
    text.normalize("NFD").replace(/[\u0300-\u036f]/g, "").toLowerCase();

  const handleSearch = () => {
    let result = [...allProperties];

    if (filters.location) {
      const search = normalizeText(filters.location);
      result = result.filter(p =>
        normalizeText(p.location || "").includes(search) ||
        normalizeText(p.name || "").includes(search) ||
        normalizeText(p.address || "").includes(search)
      );
    }

    if (filters.operation !== "all") {
      const opSearch = normalizeText(filters.operation);
      result = result.filter(p =>
        normalizeText(p.operation || "").includes(opSearch)
      );
    }

    if (filters.type !== "all") {
      const typeSearch = normalizeText(filters.type);
      result = result.filter(p =>
        normalizeText(p.name || "").includes(typeSearch) ||
        normalizeText(p.description || "").includes(typeSearch)
      );
    }

    setFilteredProperties(result);
  };

  const featured = filteredProperties.filter((p: any) => p.featured || p.destacado).slice(0, 3);
  const displayFeatured = featured.length > 0 ? featured : filteredProperties.filter(p => p.featured).slice(0, 3);

  return (
    <div className="flex flex-col gap-16 pb-16">
      {/* Hero Section */}
      <section id="inicio" className="relative h-[80vh] min-h-[600px] flex items-center justify-center">
        <div className="absolute inset-0 z-0">
          <img src="/hero-family.png" alt="Familia feliz" className="w-full h-full object-cover" />
          <div className="absolute inset-0 bg-blue-900/60 mix-blend-multiply" />
        </div>

        <div className="container relative z-10 px-4 flex flex-col items-center text-center">
          <h1 className="text-4xl md:text-6xl font-bold text-white mb-6 drop-shadow-md">
            Encuentra el hogar de tus sue├▒os
          </h1>
          <p className="text-lg md:text-xl text-blue-50 max-w-2xl mb-12 drop-shadow">
            Propiedades exclusivas con el respaldo y la confianza de Volkern Properties. Minimalismo, lujo y profesionalismo a tu alcance.
          </p>

          <div className="bg-white/10 backdrop-blur-md border border-white/20 p-6 rounded-3xl w-full max-w-5xl flex flex-col md:flex-row gap-4 items-end shadow-2xl">
            <div className="flex-1 w-full text-left">
              <label className="text-xs font-semibold text-blue-100 uppercase tracking-wider block mb-2">Ubicaci├│n</label>
              <input
                type="text"
                placeholder="┬┐D├│nde quieres vivir?"
                className="w-full h-12 px-4 rounded-xl bg-white text-slate-900 focus:outline-none focus:ring-2 focus:ring-blue-500"
                value={filters.location}
                onChange={(e) => setFilters({ ...filters, location: e.target.value })}
                onKeyDown={(e) => e.key === 'Enter' && handleSearch()}
              />
            </div>
            <div className="flex-1 w-full text-left">
              <label className="text-xs font-semibold text-blue-100 uppercase tracking-wider block mb-2">Operaci├│n</label>
              <select
                className="w-full h-12 px-4 rounded-xl bg-white text-slate-900 focus:outline-none focus:ring-2 focus:ring-blue-500 text-sm"
                value={filters.operation}
                onChange={(e) => setFilters({ ...filters, operation: e.target.value })}
              >
                <option value="all">Todas</option>
                <option value="venta">Venta</option>
                <option value="renta">Renta</option>
              </select>
            </div>
            <div className="flex-1 w-full text-left">
              <label className="text-xs font-semibold text-blue-100 uppercase tracking-wider block mb-2">Tipo</label>
              <select
                className="w-full h-12 px-4 rounded-xl bg-white text-slate-900 focus:outline-none focus:ring-2 focus:ring-blue-500 text-sm"
                value={filters.type}
                onChange={(e) => setFilters({ ...filters, type: e.target.value })}
              >
                <option value="all">Todos</option>
                <option value="Piso">Piso</option>
                <option value="Casa">Casa</option>
              </select>
            </div>
            <button
              onClick={handleSearch}
              className="h-12 px-8 bg-blue-600 hover:bg-blue-700 text-white font-bold rounded-xl transition-colors w-full md:w-auto flex-shrink-0"
            >
              Buscar
            </button>
          </div>
        </div>
      </section>

      {/* Featured Properties */}
      <section id="destacados" className="container mx-auto px-4 pt-8">
        <div className="mb-10">
          <h2 className="text-3xl font-bold text-slate-900 mb-2">Propiedades Destacadas</h2>
          <p className="text-slate-500">Selecci├│n premium de nuestras mejores oportunidades inmobiliarias.</p>
        </div>

        {loading ? (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
            {[1, 2, 3].map(i => (
              <div key={i} className="h-96 rounded-2xl bg-slate-100 animate-pulse" />
            ))}
